def hit_rate(retriever, eval_set: list[dict], k: int = 3) -> float:
    """Fraction of queries where a relevant doc appears in top-k."""
    hits = 0
    for item in eval_set:
        results = retriever.invoke(item["query"])
        retrieved_sources = {d.metadata.get("source") for d in results[:k]}
        if item["relevant_source"] in retrieved_sources:
            hits += 1
    return hits / len(eval_set)

def mean_reciprocal_rank(retriever, eval_set: list[dict]) -> float:
    """Average of 1/rank for the first relevant document."""
    rr_sum = 0.0
    for item in eval_set:
        results = retriever.invoke(item["query"])
        for rank, doc in enumerate(results, start=1):
            if doc.metadata.get("source") == item["relevant_source"]:
                rr_sum += 1.0 / rank
                break
    return rr_sum / len(eval_set)

eval_set = [
    {"query": "What is LCEL?",           "relevant_source": "lcel.txt"},
    {"query": "How does BM25 work?",      "relevant_source": "retriever.txt"},
    {"query": "LangChain framework intro","relevant_source": "intro.txt"},
]

print(f"Hit Rate @ 3: {hit_rate(retriever, eval_set):.2f}")
print(f"MRR:         {mean_reciprocal_rank(retriever, eval_set):.2f}")
